import { useState, useEffect } from "react";
import { getMovieDetails } from "../../services/Api"; // Make sure this path is correct

function MoviePopup({ movie, onClose, onDelete, onUpdate }) {
    const [details, setDetails] = useState(null);
    const [isEditing, setIsEditing] = useState(false);
    const [newTitle, setNewTitle] = useState(movie.Title || movie.title);

    useEffect(() => {
        const fetchInfo = async () => {
            // We use the ID to get the FULL plot and rating
            const data = await getMovieDetails(movie.imdbID || movie.id);
            setDetails(data);
        };
        if (movie) fetchInfo();
    }, [movie]);

    // This prevents the app from crashing while waiting for the API
    if (!details) return (
        <div className="modal">
            <div className="loader">Loading Cinematic Details...</div>
        </div>
    );

    // High-Res Image Logic
    const highResPoster = details.Poster.replace("SX300", "SX1000");

    return (
        <div className="modal" onClick={onClose}>
            <div className="modal-content netflix-style" onClick={(e) => e.stopPropagation()}>
                <button className="close-x" onClick={onClose}>&times;</button>

                <div className="modal-header-image">
                    <img src={highResPoster} alt={details.Title} />
                    <div className="modal-overlay-bottom"></div>
                </div>

                <div className="modal-body">
                    {isEditing ? (
                        <input
                            className="modal-edit-input"
                            value={newTitle}
                            onChange={(e) => setNewTitle(e.target.value)}
                            autoFocus
                        />
                    ) : (
                        <h2 className="movie-title-large">{details.Title}</h2>
                    )}

                    {/* REAL METADATA FROM API */}
                    <div className="movie-metadata">
                        <span className="year">{details.Year}</span>
                        <span className="age-tag">{details.Rated}</span>
                        <span className="runtime">{details.Runtime}</span>
                        <span className="format">4K Ultra HD</span>
                    </div>

                    {/* REAL DESCRIPTION FROM API */}
                    <p className="movie-description">{details.Plot}</p>

                    <div className="modal-buttons">
                        {isEditing ? (
                            <>
                                <button className="btn-save" onClick={() => { onUpdate(movie.imdbID, newTitle); setIsEditing(false); }}>Save</button>
                                <button className="btn-cancel" onClick={() => setIsEditing(false)}>Cancel</button>
                            </>
                        ) : (
                            <>
                                <button className="btn-edit-trigger" onClick={() => setIsEditing(true)}>Edit Title</button>
                                <button className="btn-delete" onClick={() => { onDelete(movie.imdbID); onClose(); }}>Remove from List</button>
                            </>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

export default MoviePopup;
